exercise.solution_code:
#include <iostream>

static int accumulate(int running_total, int value)
{
    return running_total + value;
}

int main()
{
    int v1{}, v2{}, v3{}, v4{};
    std::cin >> v1 >> v2 >> v3 >> v4;

    int total{ 0 };

    total = accumulate(total, v1);
    std::cout << "After adding " << v1 << ": total is " << total << '\n';

    total = accumulate(total, v2);
    std::cout << "After adding " << v2 << ": total is " << total << '\n';

    total = accumulate(total, v3);
    std::cout << "After adding " << v3 << ": total is " << total << '\n';

    total = accumulate(total, v4);
    std::cout << "After adding " << v4 << ": total is " << total << '\n';

    return 0;
}
